const express = require('express');
const app = express();

// Allowlist of valid action characters - alphanumeric, spaces, and basic punctuation
const VALID_ACTION_PATTERN = /^[a-zA-Z0-9 _\-.,;:()]+$/;
const MAX_ACTION_LENGTH = 200;

// Allowlist of known action types (optional strict mode)
const ALLOWED_ACTIONS = new Set([
  'login',
  'logout',
  'view_page',
  'update_profile',
  'delete_account',
  'create_record',
  'update_record',
  'delete_record',
  'export_data',
  'change_password',
  'view_dashboard',
  'search',
  'upload_file',
  'download_file'
]);

function sanitizeForLog(input) {
  if (typeof input !== 'string') {
    return '[invalid_input]';
  }

  // Remove newlines, carriage returns, tabs, and other control characters
  // This prevents log injection where attackers insert fake log entries
  let sanitized = input.replace(/[\r\n\t\x00-\x1f\x7f-\x9f]/g, '');

  // Truncate to maximum length
  sanitized = sanitized.substring(0, MAX_ACTION_LENGTH);

  // Validate against allowlist pattern
  if (!VALID_ACTION_PATTERN.test(sanitized)) {
    return '[invalid_characters_removed]';
  }

  return sanitized;
}

function formatTimestamp() {
  return new Date().toISOString();
}

app.get('/log-action', (req, res) => {
  const rawAction = req.query.action;

  if (!rawAction) {
    return res.status(400).json({
      error: 'Missing required query parameter: action'
    });
  }

  if (typeof rawAction !== 'string') {
    return res.status(400).json({
      error: 'Invalid action parameter type'
    });
  }

  const sanitizedAction = sanitizeForLog(rawAction);

  if (sanitizedAction === '[invalid_input]' || sanitizedAction === '[invalid_characters_removed]') {
    console.log(JSON.stringify({
      timestamp: formatTimestamp(),
      level: 'WARN',
      event: 'invalid_action_attempted',
      source_ip: req.ip,
      message: 'Rejected action with invalid characters'
    }));

    return res.status(400).json({
      error: 'Action contains invalid characters. Only alphanumeric characters, spaces, and basic punctuation are allowed.'
    });
  }

  // Use structured logging (JSON) to prevent log injection
  // Even if sanitization were bypassed, JSON structure keeps log entries atomic
  const logEntry = {
    timestamp: formatTimestamp(),
    level: 'INFO',
    event: 'user_action',
    action: sanitizedAction,
    source_ip: req.ip,
    user_agent: sanitizeForLog(req.get('User-Agent') || 'unknown')
  };

  console.log(JSON.stringify(logEntry));

  res.status(200).json({
    message: 'Action logged successfully',
    action: sanitizedAction,
    timestamp: logEntry.timestamp
  });
});

// Strict mode endpoint that only accepts actions from the allowlist
app.get('/log-action-strict', (req, res) => {
  const rawAction = req.query.action;

  if (!rawAction || typeof rawAction !== 'string') {
    return res.status(400).json({
      error: 'Missing or invalid action parameter'
    });
  }

  const normalizedAction = rawAction.trim().toLowerCase();

  if (!ALLOWED_ACTIONS.has(normalizedAction)) {
    console.log(JSON.stringify({
      timestamp: formatTimestamp(),
      level: 'WARN',
      event: 'unknown_action_attempted',
      attempted_action: sanitizeForLog(rawAction),
      source_ip: req.ip,
      message: 'Rejected action not in allowlist'
    }));

    return res.status(400).json({
      error: 'Unknown action. Allowed actions: ' + Array.from(ALLOWED_ACTIONS).join(', ')
    });
  }

  const logEntry = {
    timestamp: formatTimestamp(),
    level: 'INFO',
    event: 'user_action',
    action: normalizedAction,
    source_ip: req.ip
  };

  console.log(JSON.stringify(logEntry));

  res.status(200).json({
    message: 'Action logged successfully',
    action: normalizedAction,
    timestamp: logEntry.timestamp
  });
});

app.get('/health', (req, res) => {
  res.status(200).json({ status: 'ok' });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(JSON.stringify({
    timestamp: formatTimestamp(),
    level: 'INFO',
    event: 'server_start',
    port: PORT,
    message: 'Audit trail service started'
  }));
});

module.exports = app;